<script lang="ts">import "./ContentEditable.css";
import { onMount } from "svelte";
import { getEditor } from "./composerContext.js";
let {
  ariaActiveDescendantID = void 0,
  ariaAutoComplete = null,
  ariaControls = void 0,
  ariaDescribedBy = void 0,
  ariaExpanded = void 0,
  ariaLabel = void 0,
  ariaLabelledBy = void 0,
  ariaMultiline = void 0,
  ariaOwns = void 0,
  ariaRequired = void 0,
  autoCapitalize = void 0,
  className = "ContentEditable__root",
  id = void 0,
  role = "textbox",
  spellCheck = true,
  style = void 0,
  tabIndex = void 0,
  testid = void 0
} = $props();
let isEditable = $state(false);
const editor = getEditor();
let ref = $state(null);
onMount(() => {
  if (ref && ref.ownerDocument && ref.ownerDocument.defaultView) {
    editor.setRootElement(ref);
  } else {
    editor.setRootElement(null);
  }
  isEditable = editor.isEditable();
  return editor.registerEditableListener((currentIsEditable) => {
    isEditable = currentIsEditable;
  });
});
</script>

<!-- svelte-ignore a11y_no_noninteractive_tabindex -->
<div
  aria-activedescendant={!isEditable ? undefined : ariaActiveDescendantID}
  aria-autocomplete={!isEditable ? 'none' : ariaAutoComplete}
  aria-controls={!isEditable ? undefined : ariaControls}
  aria-describedby={ariaDescribedBy}
  aria-expanded={!isEditable
    ? undefined
    : role === 'combobox'
      ? !!ariaExpanded
      : undefined}
  aria-label={ariaLabel}
  aria-labelledby={ariaLabelledBy}
  aria-multiline={ariaMultiline}
  aria-owns={!isEditable ? null : ariaOwns}
  aria-readonly={!isEditable ? true : undefined}
  aria-required={ariaRequired}
  autocapitalize={autoCapitalize}
  class={className}
  contentEditable={isEditable}
  data-testid={testid}
  {id}
  bind:this={ref}
  {role}
  spellcheck={spellCheck}
  {style}
  tabindex={tabIndex}>
</div>
