<script lang="ts" module>
	export type OnChangeCallback = (
		value: string,
		textUpToAnchor: string | undefined,
		textAfterAnchor: string | undefined,
	) => void;
</script>

<script lang="ts">
	import { getEditor } from "../context";
	import { getEditorTextAfterAnchor, getEditorTextUpToAnchor } from "../selection";
	import { exportPlaintext } from "../utils/export";
	import { $getRoot as getRoot } from "lexical";
	import {
		BLUR_COMMAND,
		COMMAND_PRIORITY_NORMAL,
		$getSelection as getSelection,
		$isRangeSelection as isRangeSelection,
	} from "lexical";

	type Props = {
		onChange?: OnChangeCallback;
	};

	const { onChange }: Props = $props();

	const editor = getEditor();

	let text = $state<string>();

	$effect(() => {
		return editor.registerCommand(
			BLUR_COMMAND,
			() => {
				editor.read(() => {
					const currentText = exportPlaintext(getRoot());
					if (currentText === text) return;
					text = currentText;

					const selection = getSelection();
					if (!isRangeSelection(selection)) {
						return;
					}

					const textUpToAnchor = getEditorTextUpToAnchor(selection);
					const textAfterAnchor = getEditorTextAfterAnchor(selection);
					onChange?.(exportPlaintext(getRoot()), textUpToAnchor, textAfterAnchor);
				});
				return false;
			},
			COMMAND_PRIORITY_NORMAL,
		);
	});
</script>
