<script lang="ts" module></script>

<script lang="ts">import { createEmptyHistoryState } from "@lexical/history";
import {
  createEditor
} from "lexical";
import { onMount, setContext } from "svelte";
import { initializeEditor } from "./initializeEditor.js";
import {
  createSharedEditorContext,
  setEditor,
  setHistoryStateContext
} from "./composerContext.js";
import { writable } from "svelte/store";
let { initialConfig, children } = $props();
const {
  theme,
  namespace,
  nodes,
  onError,
  editorState: initialEditorState,
  editable,
  html
} = initialConfig;
const editor = createEditor({
  editable,
  html,
  namespace,
  nodes,
  onError: (error) => onError(error, editor),
  theme
});
initializeEditor(editor, initialEditorState);
setEditor(editor);
const isEditable = writable(editable !== void 0 ? editable : true);
setContext("isEditable", isEditable);
onMount(() => {
  editor.setEditable($isEditable);
  return editor.registerEditableListener((editable2) => {
    $isEditable = editable2;
  });
});
setHistoryStateContext(createEmptyHistoryState());
createSharedEditorContext();
export function getEditor() {
  return editor;
}
</script>

{@render children?.()}
