<script lang="ts">
	import ChangedFileStats from "$components/files/ChangedFileStats.svelte";
	import FileListConflicts from "$components/files/FileListConflicts.svelte";
	import FileListItems from "$components/files/FileListItems.svelte";
	import FileListProvider from "$components/files/FileListProvider.svelte";
	import emptyFolderSvg from "$lib/assets/empty-state/empty-folder.svg?raw";
	import { FILE_SELECTION_MANAGER } from "$lib/selection/fileSelectionManager.svelte";
	import { readStableSelectionKey, stableSelectionKey, type SelectionId } from "$lib/selection/key";
	import { inject } from "@gitbutler/core/context";
	import { EmptyStatePlaceholder, Icon } from "@gitbutler/ui";

	import type { ConflictEntriesObj } from "$lib/files/conflicts";
	import type { TreeStats } from "@gitbutler/but-sdk";
	import type { TreeChange } from "@gitbutler/but-sdk";
	import { t } from "$lib/i18n/index.svelte";

	type Props = {
		projectId: string;
		stackId?: string;
		selectionId: SelectionId;
		changes: TreeChange[];
		title: string;
		stats?: TreeStats;
		conflictEntries?: ConflictEntriesObj;
		draggableFiles?: boolean;
		autoselect?: boolean;
		ancestorMostConflictedCommitId?: string;
		onFileClick?: (index: number) => void;
		allowUnselect?: boolean;
		persistId?: string;
		foldedByDefault?: boolean;
		visibleRange?: { start: number; end: number };
	};

	const {
		projectId,
		stackId,
		selectionId,
		changes,
		title,
		stats,
		conflictEntries,
		draggableFiles,
		autoselect,
		ancestorMostConflictedCommitId,
		onFileClick,
		allowUnselect = true,
		persistId = "default",
		foldedByDefault = false,
		visibleRange,
	}: Props = $props();

	const idSelection = inject(FILE_SELECTION_MANAGER);
	// Turn the selection key into a string so it can be watched reactively in a consistent way.
	const stringSelectionKey = $derived(stableSelectionKey(selectionId));
	// Derive the path of the first changed file, so it can be watched reactively in a consistent way.
	const firstChangePath = $derived(changes.at(0)?.path);

	let listMode: "list" | "tree" = $state("tree");
	const hasConflicts = $derived(conflictEntries && Object.keys(conflictEntries).length > 0);
	// eslint-disable-next-line svelte/prefer-writable-derived
	let folded = $state(false);
	// Empty changesets are always folded; otherwise defer to the prop.
	$effect(() => {
		folded = changes.length === 0 && !hasConflicts ? true : foldedByDefault;
	});

	$effect(() => {
		const id = readStableSelectionKey(stringSelectionKey);
		const selection = idSelection.getById(id);
		if (firstChangePath && autoselect && selection.entries.size === 0) {
			idSelection.set(firstChangePath, selectionId, 0);
		}
	});
</script>

<div role="presentation" class="filelist-wrapper">
	<div class="filelist-container">
		<div
			class="filelist-header"
			class:folded
			role="presentation"
			ondblclick={() => {
				folded = !folded;
			}}
		>
			<button
				type="button"
				class="filelist-header__chevron"
				class:rotated={folded}
				onclick={(e) => {
					e.stopPropagation();
					folded = !folded;
				}}
				aria-label="Toggle file list"
				aria-expanded={!folded}
			>
				<Icon name="chevron-down" />
			</button>
			<ChangedFileStats
				{title}
				bind:mode={listMode}
				persistId={`changed-files-${persistId}`}
				fileCount={changes.length}
				linesAdded={stats?.linesAdded}
				linesRemoved={stats?.linesRemoved}
			/>
		</div>

		{#if !folded}
			{#if changes.length === 0 && !hasConflicts}
				<EmptyStatePlaceholder
					image={emptyFolderSvg}
					gap={0}
					topBottomPadding={14}
					bottomMargin={20}
				>
					{#snippet caption()}
						{t('file.noFilesChanged')}
					{/snippet}
				</EmptyStatePlaceholder>
			{:else}
				<FileListProvider {changes} {selectionId} {allowUnselect}>
					<FileListConflicts
						{projectId}
						{stackId}
						{conflictEntries}
						{ancestorMostConflictedCommitId}
						draggable={draggableFiles}
					/>
					<FileListItems
						{projectId}
						{stackId}
						mode={listMode}
						draggable={draggableFiles}
						{conflictEntries}
						{visibleRange}
						onselect={onFileClick && ((_change, index) => onFileClick(index))}
					/>
				</FileListProvider>
			{/if}
		{/if}
	</div>
</div>

