import { EmojiNode } from "../node/emoji";
import { GhostText } from "../node/ghostText";
import { InlineCodeNode } from "../node/inlineCode";
import { MentionNode } from "../node/mention";
import { HeadingNode, QuoteNode, ListNode, ListItemNode, HorizontalRuleNode, ImageNode, KeywordNode, HashtagNode, AutoLinkNode, LinkNode, CodeNode, CodeHighlightNode, TableNode, TableCellNode, TableRowNode, $createParagraphNode, $createTextNode, $getRoot, } from "svelte-lexical";
export function standardConfig(args) {
    const { namespace, theme, onError, initialText } = args;
    return {
        editable: true,
        theme,
        namespace,
        onError,
        editorState: (editor) => {
            if (initialText) {
                editor.update(() => {
                    const paragraph = $createParagraphNode();
                    const text = $createTextNode(initialText);
                    paragraph.append(text);
                    $getRoot().append(paragraph);
                    $getRoot().selectEnd();
                });
            }
        },
        nodes: [
            LinkNode,
            AutoLinkNode,
            ListNode,
            ListItemNode,
            TableNode,
            TableCellNode,
            TableRowNode,
            HorizontalRuleNode,
            ImageNode,
            CodeNode,
            HeadingNode,
            LinkNode,
            ListNode,
            ListItemNode,
            QuoteNode,
            HashtagNode,
            CodeHighlightNode,
            EmojiNode,
            KeywordNode,
            InlineCodeNode,
            MentionNode,
            GhostText,
        ],
    };
}
