<script lang="ts">
	import CommitTimelineNode from "$components/commit/CommitTimelineNode.svelte";
	import CommitTitle from "$components/commit/CommitTitle.svelte";
	import { URL_SERVICE } from "$lib/backend/url";
	import { type CommitStatusType } from "$lib/commits/commit";
	import { inject } from "@gitbutler/core/context";
	import { Avatar, Icon, TestId } from "@gitbutler/ui";
	import { focusable } from "@gitbutler/ui/focus/focusable";

	import { slide } from "svelte/transition";
	import type { Reaction } from "$lib/irc/ircEndpoints";
	import type { Snippet } from "svelte";
	import { t } from "$lib/i18n/index.svelte";

	type BaseProps = {
		type: CommitStatusType;
		branchName?: string;
		commitId: string;
		commitMessage: string;
		committedAt: number;
		author?: { name: string; email: string; gravatarUrl: string };
		tooltip?: string;
		first?: boolean;
		lastCommit?: boolean;
		lastBranch?: boolean;
		selected?: boolean;
		/** When true, expand the changed files panel. Defaults to `selected`. */
		expandChangedFiles?: boolean;
		opacity?: number;
		borderTop?: boolean;
		disableCommitActions?: boolean;
		active?: boolean;
		hasConflicts?: boolean;
		busy?: boolean;
		disabled?: boolean;
		editable?: boolean;
		gerritReviewUrl?: string;
		reactions?: Reaction[];
		menu?: Snippet<[{ rightClickTrigger: HTMLElement }]>;
		changedFiles?: Snippet;
		onclick?: (event: MouseEvent) => void;
	};

	type RemoteStatusProps = {
		type: "LocalOnly" | "Integrated" | "Remote";
	};

	type LocalAndRemoteWithActions = {
		type: "LocalAndRemote";
		disableCommitActions: false;
		diverged: boolean;
	};

	type LocalAndRemoteDisabled = {
		type: "LocalAndRemote";
		disableCommitActions: true;
		diverged: boolean;
	};

	type WithStackId = {
		disableCommitActions: false;
		stackId?: string;
	};

	type WithoutStackId = {
		disableCommitActions: true;
	};

	type Props = BaseProps &
		(RemoteStatusProps | LocalAndRemoteWithActions | LocalAndRemoteDisabled) &
		(WithStackId | WithoutStackId);

	const {
		commitMessage,
		author,
		tooltip,
		first,
		lastCommit,
		lastBranch,
		selected,
		expandChangedFiles,
		opacity,
		borderTop,
		disabled,
		hasConflicts,
		busy,
		active,
		editable,
		gerritReviewUrl,
		reactions,
		onclick,
		menu,
		changedFiles,
		...args
	}: Props = $props();

	const shouldExpandFiles = $derived(expandChangedFiles ?? selected);

	let container = $state<HTMLDivElement>();

	const urlService = inject(URL_SERVICE);

	function extractReviewId(url: string | undefined): string | null {
		if (!url) return null;
		// Extract review ID from URLs like: http://15a45d4cba1a/c/gerrit-test/+/41
		const match = url.match(/\+\/(\d+)/);
		return match?.[1] ?? null;
	}

	async function openGerritReview() {
		if (gerritReviewUrl) {
			await urlService.openExternalUrl(gerritReviewUrl);
		}
	}
</script>

<!-- svelte-ignore a11y_click_events_have_key_events -->
<div class="commit-row-wrapper" class:first class:last={lastCommit}>
	<div
		data-testid={TestId.CommitRow}
		data-commit-id={args.disableCommitActions ? undefined : args.commitId}
		bind:this={container}
		role="button"
		tabindex="0"
		aria-label={t('commit.listItem.commitRow')}
		class="commit-row"
		class:selected
		class:active
		style:opacity
		class:has-conflicts={hasConflicts}
		class:border-top={borderTop || first}
		class:disabled
		{onclick}
		use:focusable={{
			onAction: () => onclick?.(new MouseEvent("click")),
			focusable: true,
		}}
	>
		{#if selected}
			<div
				class="commit-row__select-indicator"
				class:active
				in:slide={{ axis: "x", duration: 150 }}
			></div>
		{/if}

		{#if !selected && !args.disableCommitActions}
			<div class="commit-row__drag-handle">
				<Icon name="drag-vertical" />
			</div>
		{/if}

		<CommitTimelineNode
			commitStatus={args.type}
			diverged={args.type === "LocalAndRemote" ? (args.diverged ?? false) : false}
			{tooltip}
			{lastCommit}
			{lastBranch}
			{hasConflicts}
		/>

		<div class="commit-content" class:has-conflicts={hasConflicts}>
			{#if hasConflicts}
				<div class="commit-conflict-indicator">
					<Icon name="warning" />
				</div>
			{/if}

			{#if author}
				<div class="commit-author-avatar">
					<Avatar
						srcUrl={author.gravatarUrl}
						username={author.name}
						tooltip={`${author.name} (${author.email})`}
						size="medium"
					/>
				</div>
			{/if}

			<div class="commit-name truncate">
				<CommitTitle {commitMessage} truncate className="text-13 text-semibold" {editable} />
				{#if gerritReviewUrl}
					{@const reviewId = extractReviewId(gerritReviewUrl)}
					{#if reviewId}
						<!-- svelte-ignore a11y_click_events_have_key_events -->
						<div
							class="gerrit-review-pill"
							role="button"
							tabindex="0"
							onclick={openGerritReview}
							title={t('commit.listItem.openGerritReview', { reviewId })}
						>
							<span class="text-11 text-semibold">{reviewId}</span>
						</div>
					{/if}
				{/if}
				{#if reactions && reactions.length > 0}
					{@const grouped = Object.values(
						reactions.reduce(
							(acc, r) => {
								const entry = acc[r.reaction] ?? {
									emoji: r.reaction,
									count: 0,
									senders: [] as string[],
								};
								entry.count++;
								entry.senders.push(r.sender);
								acc[r.reaction] = entry;
								return acc;
							},
							{} as Record<string, { emoji: string; count: number; senders: string[] }>,
						),
					)}
					{#each grouped as group}
						<div class="reaction-pill" title={group.senders.join(", ")}>
							<span class="text-12">{group.emoji}</span>
							{#if group.count > 1}
								<span class="text-11 text-bold">{group.count}</span>
							{/if}
						</div>
					{/each}
				{/if}
			</div>

			{#if busy}
				<div class="commit-busy-spinner">
					<Icon name="spinner" size={14} />
				</div>
			{:else if !args.disableCommitActions}
				{@render menu?.({ rightClickTrigger: container })}
			{/if}
		</div>
	</div>

	{#if shouldExpandFiles && changedFiles}
		<div class="changed-files-container">
			<CommitTimelineNode commitStatus={args.type} hideDot height="0.375rem" />
			{@render changedFiles()}
			<CommitTimelineNode commitStatus={args.type} hideDot height="1rem" />
		</div>
	{/if}
</div>

